                internal void BuildString(StringBuilder builder)
                {
                    if (_buffer == null)
                    {
                        return;
                    }

                    builder.Append('(');
                    builder.Append("LegID=");
                    builder.Append("'");
                    for (int i = 0; i < LegIDLength && this.GetLegID(i) > 0; ++i)
                    {
                        builder.Append((char)this.GetLegID(i));
                    }
                    builder.Append("'");
                    builder.Append('|');
                    builder.Append("Ratio=");
                    builder.Append(this.Ratio);
                    builder.Append('|');
                    builder.Append("Quantity=");
                    builder.Append(this.Quantity);
                    builder.Append('|');
                    builder.Append("PositionEffect=");
                    builder.Append(this.PositionEffect);
                    builder.Append('|');
                    builder.Append("LegSide=");
                    builder.Append(this.LegSide);
                    builder.Append('|');
                    builder.Append("Symbol=");
                    builder.Append("'");
                    for (int i = 0; i < SymbolLength && this.GetSymbol(i) > 0; ++i)
                    {
                        builder.Append((char)this.GetSymbol(i));
                    }
                    builder.Append("'");
                    builder.Append(')');

                }
        }

        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new SendOrderMinimal();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[SendOrderMinimal](sbeTemplateId=");
            builder.Append(SendOrderMinimal.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(SendOrderMinimal.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != SendOrderMinimal.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(SendOrderMinimal.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != SendOrderMinimal.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(SendOrderMinimal.BlockLength);
            builder.Append("):");

            builder.Append("LocalID=");
            builder.Append("'");
            for (int i = 0; i < LocalIDLength && this.GetLocalID(i) > 0; ++i)
            {
                builder.Append((char)this.GetLocalID(i));
