            builder.Append(this.RiskCheckId);
            builder.Append('|');
            builder.Append("NoLegs=[");
            var noLegs = this.NoLegs;
            if (noLegs.Count > 0)
            {
                var first = true;
                while (noLegs.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    noLegs.Next().BuildString(builder);
